await page.setViewportSize({ width: 390, height: 800 });
return await page.evaluate(() => {
  const cx = 195, cy = 600; // punto en el área de contenido (móvil)
  const stack = document.elementsFromPoint(cx, cy).slice(0, 6).map(el => {
    const cs = getComputedStyle(el);
    return {
      tag: el.tagName.toLowerCase(),
      cls: (el.getAttribute('class') || '').slice(0, 60),
      pos: cs.position,
      touchAction: cs.touchAction,
      overflow: cs.overflow,
      pointerEvents: cs.pointerEvents,
      z: cs.zIndex,
    };
  });
  const root = document.documentElement;
  const body = document.body;
  return {
    scrollingElement: document.scrollingElement === root ? 'html' : 'body/other',
    htmlOverflowY: getComputedStyle(root).overflowY,
    bodyOverflowY: getComputedStyle(body).overflowY,
    htmlHeight: root.scrollHeight,
    clientHeight: root.clientHeight,
    canScroll: root.scrollHeight > root.clientHeight,
    htmlTouchAction: getComputedStyle(root).touchAction,
    bodyTouchAction: getComputedStyle(body).touchAction,
    stackAtContent: stack,
  };
});

